window.PACTO.acts["reg-2013-1296"]={"label": "REGOLAMENTO (UE) N. 1296/2013 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 1296/2013", "file": "ext-reg-2013-1296.html", "external": true, "version": "originale GU", "eurlex": "https://eur-lex.europa.eu/eli/reg/2013/1296/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il presente regolamento istituisce un programma dell'Unione europea per l'occupazione e l'innovazione sociale (\"programma\") che ha lo scopo di contribuire all'attuazione di Europa 2020, compresi i suoi obiettivi prioritari, i suoi orientamenti integrati e le sue iniziative faro, fornendo un sostegno finanziario alla realizzazione degli obiettivi dell'Unione, per quanto riguarda la promozione di un elevato livello di occupazione di qualità e sostenibile, la garanzia di un'adeguata e dignitosa protezione sociale, la lotta contro l'esclusione sociale e la povertà e il miglioramento delle condizioni di lavoro.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il programma è attuato dal 1<span class=\"oj-super\">o</span> gennaio 2014 al 31 dicembre 2020.</p>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"oj-normal\">Ai fini del presente regolamento si applicano le definizioni seguenti:</p>"], [null, "<p class=\"oj-normal\">1)   <span class=\"oj-bold\">\"impresa sociale\"</span>: un'impresa, qualunque sia la sua forma giuridica, che:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">conformemente al suo atto costitutivo, al suo statuto o a qualsiasi altro documento giuridico istituitivo dell'impresa, ha come obiettivo primario la realizzazione di un impatto sociale positivo e misurabile e non finalità lucrative per i proprietari, soci e azionisti, e qualora l'impresa:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornisca beni o servizi che producono un elevato rendimento sociale, e/o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">impieghi un metodo di produzione di beni o servizi che incorpora il proprio obiettivo sociale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">utilizza i profitti in primo luogo per raggiungere il proprio obiettivo primario e ha procedure e regole predefinite riguardanti qualsiasi distribuzione dei profitti ad azionisti e proprietari che garantiscono che tale distribuzione non pregiudichi l'obiettivo primario; e</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">è gestita in modo imprenditoriale, responsabile e trasparente, in particolare coinvolgendo i lavoratori, i clienti e gli attori interessati dalle sue attività;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">2)   <span class=\"oj-bold\">\"microcredito\"</span>: un prestito dell'importo massimo di 25 000 EUR;</p>"], [null, "<p class=\"oj-normal\">3)   <span class=\"oj-bold\">\"microimpresa\"</span>: un'impresa, compreso un lavoratore indipendente, che occupa meno di 10 persone e il cui fatturato annuo o bilancio annuo totale non è superiore ai 2 milioni di EUR, secondo la raccomandazione 2003/361/CE della Commissione (<span class=\"oj-super oj-note-tag\">13</span>);</p>"], [null, "<p class=\"oj-normal\">4)   <span class=\"oj-bold\">\"microfinanza\"</span>: garanzie, microcrediti, equity e quasi-equity estesi a persone e microimprese che hanno difficoltà di accesso al credito;</p>"], [null, "<p class=\"oj-normal\">5)   <span class=\"oj-bold\">\"innovazioni sociali\"</span>: le innovazioni che hanno sia finalità sia mezzi sociali, e in particolare quelle che fanno riferimento allo sviluppo e all'attuazione di nuove idee (riguardanti prodotti, servizi e modelli) che rispondono a esigenze sociali e, contemporaneamente, creano nuovi rapporti o collaborazioni sociali, fornendo un beneficio alla società e promuovendo la capacità di agire della stessa;</p>"], [null, "<p class=\"oj-normal\">6)   <span class=\"oj-bold\">\"sperimentazione di politiche sociali\"</span>: gli interventi programmatici che offrono una risposta innovativa alle esigenze sociali, attuati su piccola scala e in condizioni che garantiscono la possibilità di misurare tale impatto,prima che siano ripetuti su scala più ampia in caso di risultati convincenti.</p>"]]}, "3": {"label": "Articolo 3", "heading": "Struttura del programma", "anchor": "art_3", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il programma si articola nei tre seguenti assi di complementarità:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'asse \"Progress\", che sostiene lo sviluppo, l'attuazione, il monitoraggio e la valutazione degli strumenti e delle politiche dell'Unione di cui all'articolo 1 e al pertinente diritto dell'Unione e che promuove l'elaborazione politica, l'innovazione sociale e il progresso sociale basati su dati di fatto, in collaborazione con le parti sociali, le organizzazioni della società civile e gli organismi pubblici e privati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'asse \"EURES\", che sostiene attività svolte da EURES, ossia i servizi specializzati designati dagli Stati del SEE e dalla Confederazione svizzera, insieme alle parti sociali, agli altri prestatori di servizi per l'impiego e ad altre parti interessate, per sviluppare gli scambi e la diffusione di informazioni e altre forme di cooperazione, quali i partenariati transfrontalieri, per promuovere la mobilità geografica volontaria dei lavoratori su base equa e per contribuire a un elevato livello di occupazione sostenibile e di qualità;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'asse \"Microfinanza e imprenditoria sociale\", che incrementa l'accesso ai finanziamenti e la disponibilità per le persone fisiche e giuridiche, in conformità dell'articolo 26.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le disposizioni comuni di cui al presente titolo si applicano a tutti e tre gli assi indicati al paragrafo 1, lettere a), b) e c), in aggiunta alle disposizioni specifiche del titolo II.</p>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Obiettivi generali", "anchor": "art_4", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il programma persegue i seguenti obiettivi generali:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rafforzare l'adesione degli attori politici a tutti i livelli e realizzare azioni concrete, coordinate e innovative sia a livello di Unione che a livello degli Stati membri, per quanto riguarda gli obiettivi dell'Unione nei settori di cui all'articolo 1, in stretta collaborazione con le parti sociali, le organizzazioni della società civile e gli organismi pubblici e privati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostenere lo sviluppo di sistemi di protezione sociale e mercati del lavoro adeguati, accessibili ed efficienti e facilitare le riforme, nei settori di cui all'articolo 1, in particolare promuovendo il lavoro dignitoso e adeguate condizioni di lavoro, la cultura della prevenzione per la salute e la sicurezza sul luogo di lavoro, un equilibrio più sano tra vita professionale e vita privata, il buon governo per gli obiettivi sociali, compresa la convergenza, nonché l'apprendimento reciproco e l'innovazione sociale;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">assicurare che il diritto dell'Unione sulle questioni relative ai settori di cui all'articolo 1 sia applicato in modo efficace e, se necessario, contribuire alla modernizzazione del diritto dell'Unione in linea con i principi del lavoro dignitoso e in considerazione dei principi della regolamentazione intelligente;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">promuovere la mobilità geografica volontaria dei lavoratori su base equa e accrescere le possibilità di impiego sviluppando mercati del lavoro nell'Unione di alta qualità e inclusivi, aperti e accessibili a tutti, rispettando al contempo i diritti dei lavoratori in tutta l'Unione, compresa la libertà di circolazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">promuovere l'occupazione e l'inclusione sociale, migliorando la disponibilità e l'accessibilità della microfinanza per le persone vulnerabili che desiderano avviare una microimpresa e per le microimprese già operanti, e facilitando l'accesso ai finanziamenti per le imprese sociali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nel perseguire tali obiettivi, il programma, nell'insieme dei suoi assi e delle sue azioni, si propone di:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">prestare un'attenzione particolare ai gruppi vulnerabili, quali i giovani;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">promuovere la parità tra uomini e donne, anche mediante l'integrazione della prospettiva di genere nelle altre politiche e, se del caso, nell'elaborazione del bilancio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">combattere le discriminazioni fondate sul sesso, la razza o l'origine etnica, la religione o le convinzioni personali, la disabilità, l'età o le tendenze sessuali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">promuovere un elevato livello di occupazione sostenibile e di qualità, garantire una protezione sociale adeguata e dignitosa, combattere la disoccupazione a lungo termine e lottare contro la povertà e l'esclusione sociale, nella definizione e nell'attuazione delle politiche e delle azioni dell'Unione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Bilancio", "anchor": "art_5", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La dotazione finanziaria per l'attuazione del programma per il periodo dal 1<span class=\"oj-super\">o</span> gennaio 2014 al 31 dicembre 2020 ammonta a 919 469 000 EUR a prezzi correnti.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Agli assi di cui all'articolo 3, paragrafo 1, sono destinate le seguenti percentuali indicative:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il 61 % all'asse \"Progress\";</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il 18 % all'asse \"EURES\";</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">il 21 % all'asse \"Microfinanza e imprenditoria sociale\".</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione può utilizzare sino al 2 % della dotazione finanziaria di cui al paragrafo 1 per finanziare le spese di funzionamento a sostegno dell'attuazione del programma.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Commissione può utilizzare la dotazione finanziaria di cui al paragrafo 1 per finanziare l'assistenza tecnica e/o amministrativa, in particolare per quanto riguarda la revisione contabile, le traduzioni effettuate all'esterno, le riunioni di esperti e le attività di informazione e di comunicazione a beneficio reciproco della Commissione e dei beneficiari.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Gli stanziamenti annuali sono autorizzati dal Parlamento europeo e dal Consiglio entro i limiti del quadro finanziario pluriennale.</p>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Azioni comuni", "anchor": "art_6", "frags": [[null, "<p class=\"oj-normal\">Le azioni ammissibili nell'ambito del programma possono essere realizzate congiuntamente ad altri strumenti dell'Unione, purché tali azioni perseguano gli obiettivi comuni al programma e agli altri strumenti in questione.</p>"]]}, "7": {"label": "Articolo 7", "heading": "Coerenza e complementarità", "anchor": "art_7", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione, in cooperazione con gli Stati membri, assicura che le attività realizzate nell'ambito del programma siano coerenti con le altre azioni dell'Unione e siano ad esse complementari, quali i Fondi strutturali e di investimento europei (ESIF), come specificato nel quadro strategico comune stabilito al regolamento (UE) n. 1303/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">14</span>), e in particolare il FSE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il programma integra altri programmi dell'Unione, fatte salve le procedure specifiche di tali programmi. Non sono ammesse duplicazioni di finanziamenti a fronte degli stessi costi ammissibili e sono sviluppate strette sinergie tra il programma, altri programmi dell'Unione e gli ESIF, in particolare il FSE.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le attività sostenute dal programma sono conformi al diritto dell'Unione e nazionale, ivi comprese le norme sugli aiuti di Stato, e alle convenzioni fondamentali dell'OIL.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La coerenza e la complementarità sono altresì assicurate mediante uno stretto coinvolgimento delle autorità locali e regionali.</p>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Cooperazione con gli organi competenti", "anchor": "art_8", "frags": [[null, "<p class=\"oj-normal\">La Commissione stabilisce i rapporti necessari con il comitato per l'occupazione, il comitato per la protezione sociale, il comitato consultivo sulla salute e la sicurezza sul luogo di lavoro, il gruppo di direttori generali per le relazioni industriali e il comitato consultivo sulla libertà di circolazione dei lavoratori per informarli regolarmente e debitamente dei progressi compiuti nell'attuazione del programma. La Commissione informa anche gli altri comitati che si occupano di politiche, strumenti e azioni aventi attinenza con il programma.</p>"]]}, "9": {"label": "Articolo 9", "heading": "Diffusione dei risultati e comunicazione", "anchor": "art_9", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione informa le parti interessate dell'Unione, comprese le parti sociali e le organizzazioni della società civile, in merito ai risultati dell'attuazione del programma e le invita ad uno scambio di opinioni in materia.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   I risultati delle azioni realizzate nell'ambito del programma sono regolarmente e adeguatamente comunicati e divulgati al Parlamento europeo, al Consiglio, al Comitato economico e sociale europeo e al Comitato delle regioni, nonché alle parti sociali e al pubblico, per ottimizzarne l'impatto e la sostenibilità e il valore aggiunto per l'Unione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le attività di comunicazione contribuiscono anche alla comunicazione istituzionale delle priorità politiche dell'Unione nella misura in cui sono relative agli obiettivi generali del presente regolamento, e forniscono informazioni in merito a tali priorità.</p>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Disposizioni finanziarie", "anchor": "art_10", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione gestisce il programma in conformità del regolamento finanziario.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La convenzione di sovvenzione precisa quale parte del contributo finanziario dell'Unione sarà basata sul rimborso dei costi ammissibili effettivi e quale parte sarà basata su tassi forfettari, costi unitari o importi forfettari.</p>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Tutela degli interessi finanziari dell'Unione", "anchor": "art_11", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione adotta le opportune misure di prevenzione dirette a garantire che, quando sono attuate azioni finanziate nel quadro del presente programma, gli interessi finanziari dell'Unione siano protetti contro la frode, la corruzione e ogni altra attività illegale mediante controlli efficaci e, nel caso in cui siano rilevate irregolarità, siano recuperate le risorse in primo luogo attraverso compensazioni di importi indebitamente versati, ma, se del caso, imponendo sanzioni efficaci, proporzionate e dissuasive, conformemente all'articolo 325 TFUE, al regolamento (CE, Euratom) n. 2988/95 del Consiglio (<span class=\"oj-super oj-note-tag\">15</span>) e al regolamento finanziario.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione o i suoi rappresentanti e la Corte dei conti hanno la facoltà di sottoporre a revisione contabile, in base a documenti e controlli sul posto, tutti i beneficiari di sovvenzioni, i contraenti e i subcontraenti che hanno ottenuto fondi dell'Unione nell'ambito del programma.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   L'Ufficio europeo per la lotta antifrode (OLAF) può effettuare indagini, inclusi controlli e verifiche sul posto, conformemente alle disposizioni e alle procedure stabilite dal regolamento (UE, Euratom) n. 883/2013 del Parlamento europeo e del Consiglio (<span class=\"oj-super oj-note-tag\">16</span>) e dal regolamento (Euratom, CE) n. 2185/96 del Consiglio (<span class=\"oj-super oj-note-tag\">17</span>), per accertare eventuali casi di frodi, corruzione o altre attività illecite lesive degli interessi finanziari dell’Unione in relazione a convenzioni di sovvenzione o decisioni di sovvenzione o contratti finanziati nel quadro del programma.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Fatti salvi i paragrafi 1, 2 e 3, i contratti, le convenzioni di sovvenzione e le decisioni di sovvenzione risultanti dall'attuazione del presente programma contengono disposizioni che autorizzano espressamente la Commissione, la Corte dei conti e l'OLAF a condurre gli audit e le indagini di cui a tali paragrafi, in conformità delle rispettive competenze.</p>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Monitoraggio", "anchor": "art_12", "frags": [[null, "<p class=\"oj-normal\">Al fine di monitorare regolarmente il programma e di adattare secondo le necessità le sue priorità di azione e di finanziamento, la Commissione elabora una prima relazione di monitoraggio qualitativa e quantitativa relativa al primo anno, seguita da tre relazioni relative a bienni consecutivi e le trasmette al Parlamento europeo e al Consiglio. Le relazioni sono trasmesse per conoscenza anche al Comitato economico e sociale europeo e al Comitato delle regioni. Le relazioni hanno per oggetto i risultati del programma e la misura in cui nelle sue attività sono stati applicati i principi della parità tra uomini e donne e dell'integrazione della prospettiva di genere ed sono state anche prese in considerazione le considerazioni sul tema della non discriminazione, comprese le questioni relative all'accessibilità. Le relazioni sono messe a disposizione del pubblico al fine di migliorare la trasparenza del programma.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Valutazione", "anchor": "art_13", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Entro il 1<span class=\"oj-super\">o</span> luglio 2017 è effettuata una valutazione intermedia del programma per misurare, in termini qualitativi e quantitativi, i progressi compiuti nel conseguimento degli obiettivi del programma, per rispondere al contesto sociale all'interno dell'Unione e alle eventuali modifiche principali introdotte dalla legislazione unionale, per determinare se le risorse del programma siano state utilizzate in modo efficiente e per stabilire il suo valore aggiunto per l'Unione. I risultati di tale valutazione intermedia sono presentati al Parlamento europeo e al Consiglio.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Se da una valutazione di cui al paragrafo 1 del presente articolo, o da qualsiasi valutazione effettuata a norma dell'articolo 19 della decisione n. 1672/2006/CE o dell'articolo 9 della decisione n. 283/2010/UE emerge che il programma presenta gravi carenze, la Commissione presenta, se del caso, al Parlamento europeo e al Consiglio una proposta contenente opportune modifiche del programma, che tengano conto dei risultati della valutazione.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Prima di presentare una proposta di proroga del programma oltre il 2020, la Commissione presenta al Parlamento europeo, al Consiglio, al Comitato economico e sociale europeo e al Comitato delle regioni una valutazione dei punti di forza e delle debolezze del programma nel periodo 2014-2020.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Entro il 31 dicembre 2022 la Commissione procede a una valutazione ex post per misurare l'impatto e il valore aggiunto per l'Unione del programma e trasmette una relazione contenente tale valutazione al Parlamento europeo, al Consiglio, al Comitato economico e sociale europeo e al Comitato delle regioni. Tale relazione è resa pubblica.</p>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Sezioni tematiche e finanziamento", "anchor": "art_14", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   L'asse Progress sostiene le azioni di una o più delle sezioni tematiche elencate alle lettere a), b) e c). Per l'intero periodo del programma, la dotazione indicativa di cui all'articolo 5, paragrafo 2, lettera a), è ripartita tra le diverse sezioni secondo le seguenti percentuali minime:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">occupazione, in particolare la lotta contro la disoccupazione giovanile: 20 %;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">protezione e inclusione sociali nonché riduzione e prevenzione della povertà: 50 %;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">condizioni di lavoro: 10 %.</p>\n</td>\n</tr>\n</tbody>\n</table>\n<p class=\"oj-normal\">Il restante importo è assegnato a una o più sezioni tematiche di cui alle lettere a), b) o c) o a una combinazione delle stesse.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Dal 15 al 20 % della dotazione complessiva per l'asse \"Progress\", nell'ambito delle sue varie sezioni tematiche, è destinato alla promozione della sperimentazione sociale come metodo per testare e valutare soluzioni innovative in vista di una loro utilizzazione su più ampia scala.</p>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Obiettivi specifici", "anchor": "art_15", "frags": [[null, "<p class=\"oj-normal\">Oltre agli obiettivi generali di cui all'articolo 4, l'asse \"Progress\" persegue i seguenti obiettivi specifici:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppare e diffondere conoscenze analitiche comparative di elevata qualità, per garantire che le politiche dell'Unione nei settori di cui all'articolo 1 si fondino su dati attendibili e rispondano alle esigenze, alle sfide e alle condizioni dei singoli Stati membri e degli altri paesi che partecipano al programma;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilitare uno scambio di informazioni efficiente e inclusivo, l'apprendimento reciproco e il dialogo sulle politiche dell'Unione nei settori di cui all'articolo 1, a livello unionale, nazionale e internazionale per assistere gli Stati membri e gli altri paesi che partecipano al programma nell'elaborazione delle loro politiche e gli Stati membri nell'attuazione del diritto dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornire sostegno finanziario alla sperimentazione delle innovazioni della politica sociale e del mercato del lavoro e, ove opportuno, al rafforzamento della capacità degli attori principali di progettare e attuare la sperimentazione di politiche sociali nonché l'accessibilità delle relative conoscenze e competenze;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">fornire sostegno finanziario alle organizzazioni dell'Unione e nazionali per rafforzare la loro capacità di sviluppare, promuovere e sostenere l'attuazione degli strumenti e delle politiche dell'Unione di cui all'articolo 1 e al pertinente diritto dell'Unione.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "16": {"label": "Articolo 16", "heading": "Tipi di azione", "anchor": "art_16", "frags": [[null, "<p class=\"oj-normal\">Possono essere finanziati nell'ambito dell'asse \"Progress\" i seguenti tipi di azione:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">1.</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Attività analitiche:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">raccolta di dati e statistiche, tenendo conto di criteri sia qualitativi che quantitativi, e sviluppo di metodologie comuni, classificazioni, microsimulazioni, indicatori e parametri di confronto, se del caso suddivisi per genere e gruppo di età;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sondaggi, studi, analisi e relazioni, anche tramite il finanziamento di reti di esperti e lo sviluppo di competenze sulle sezioni tematiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">valutazioni e analisi di impatto qualitative e quantitative effettuate da organismi pubblici e privati;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">monitoraggio e valutazione del recepimento e dell'applicazione del diritto dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">preparazione e attuazione della sperimentazione di politiche sociali come metodo per testare e valutare soluzioni innovative in vista di una loro utilizzazione su più ampia scala;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">diffusione dei risultati di tali attività analitiche.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">2.</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Attività di apprendimento reciproco, sensibilizzazione e diffusione:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambi e diffusione di buone prassi, approcci ed esperienze innovativi, esame tra pari, analisi comparativa e apprendimento reciproco a livello europeo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">eventi, conferenze e seminari della presidenza del Consiglio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">formazione di operatori giuridici e politici;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">redazione e pubblicazione di guide, rapporti e materiale didattico e misure concernenti l'informazione, la comunicazione e la copertura mediatica delle iniziative sostenute dal programma;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">attività di informazione e comunicazione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppo e manutenzione di sistemi di informazione finalizzati allo scambio e alla diffusione di informazioni sulla politica e sulla legislazione dell'Unione e sul mercato del lavoro.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">3.</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">Sostegno per quanto riguarda:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le spese di funzionamento delle principali reti a livello di Unione le cui attività sono connesse agli obiettivi dell'asse \"Progress\" e contribuiscono al loro conseguimento;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppo delle capacità delle amministrazioni nazionali e dei servizi specializzati responsabili della promozione della mobilità geografica designati dagli Stati membri e degli operatori del microcredito;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzazione di gruppi di lavoro composti da rappresentanti nazionali, incaricati di monitorare l'attuazione del diritto dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">creazione di reti e cooperazione tra organismi specializzati e altre parti interessate, autorità nazionali, regionali e locali e servizi per l'impiego a livello europeo;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">finanziamento di osservatori a livello europeo, anche per le principali sezioni tematiche;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">scambio di personale tra amministrazioni nazionali.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "17": {"label": "Articolo 17", "heading": "Cofinanziamento dell'Unione", "anchor": "art_17", "frags": [[null, "<p class=\"oj-normal\">Nei casi in cui le attività dell'asse \"Progress\" siano finanziate a seguito di un invito a presentare proposte, esse possono beneficiare di un cofinanziamento dell'Unione non superiore, di norma, all'80 % della spesa totale ammissibile. Un eventuale sostegno finanziario superiore a tale massimale è concesso soltanto in circostanze eccezionali debitamente giustificate.</p>"]]}, "18": {"label": "Articolo 18", "heading": "Partecipazione", "anchor": "art_18", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Possono partecipare all'asse \"Progress\":</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i paesi del SEE, in conformità all'accordo SEE, e gli Stati membri dell'EFTA;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i paesi candidati e i candidati potenziali, conformemente ai principi generali e alle condizioni e modalità generali stabiliti dagli accordi quadro conclusi con tali paesi ai fini della loro partecipazione a programmi dell'Unione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'asse \"Progress\" è aperto a tutti gli organismi, gli operatori e le istituzioni del settore pubblico e di quello privato, in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">autorità nazionali, regionali e locali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">servizi per l'impiego;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organismi specializzati previsti dal diritto dell'Unione;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">parti sociali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">organizzazioni non governative;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituti di istruzione superiore e istituti di ricerca;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">g)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">esperti in valutazione e in valutazione d'impatto;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">h)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">istituti statistici nazionali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">mezzi di comunicazione.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La Commissione può cooperare con le organizzazioni internazionali, in particolare con il Consiglio d'Europa, l'OCSE, l'OIL, con altri organismi delle Nazioni Unite e con la Banca mondiale.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   La Commissione può cooperare con paesi terzi che non partecipano al programma. Rappresentanti di tali paesi terzi possono partecipare a manifestazioni di interesse comune (quali conferenze, laboratori e seminari) che si svolgono in paesi partecipanti al programma e il costo della loro partecipazione può essere coperto dal programma.</p>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Sezioni tematiche e finanziamento", "anchor": "art_19", "frags": [[null, "<p class=\"oj-normal\">L'asse EURES sostiene le azioni in una o più delle sezioni tematiche di cui alle lettere a), b) e c). Per l'intero periodo del programma, la dotazione indicativa di cui all'articolo 5, paragrafo 2, lettera b), è ripartita tra le diverse sezioni secondo le seguenti percentuali minime:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">trasparenza delle offerte e delle domande di lavoro e delle relative informazioni per chi cerca e per chi offre lavoro: 32 %;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppo di servizi di assunzione e collocamento dei lavoratori mediante l'intermediazione tra l'offerta e la domanda di lavoro a livello di Unione, in particolare i programmi mirati di mobilità: 30 %;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">partenariati transfrontalieri: 18 %.</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">Ogni importo restante è assegnato a una o più delle sezioni tematiche di cui alle lettere a), b) o c) o a una combinazione delle stesse.</p>"]]}, "20": {"label": "Articolo 20", "heading": "Obiettivi specifici", "anchor": "art_20", "frags": [[null, "<p class=\"oj-normal\">Oltre agli obiettivi generali di cui all'articolo 4, l'asse \"EURES\" persegue i seguenti obiettivi specifici:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">rendere trasparenti per chi cerca e per chi offre lavoro le offerte e le richieste di lavoro, le informazioni e consulenze corrispondenti, nonché le relative informazioni, ad esempio quelle concernenti le condizioni di vita e di lavoro. Tale obiettivo è conseguito mediante lo scambio e la diffusione a livello transnazionale, interregionale e transfrontaliero, attraverso l'utilizzo di moduli standard di interoperabilità per le offerte e le domande di lavoro, così come mediante altri strumenti idonei, ad esempio consulenza e tutoraggio individuali, in particolare per i meno qualificati;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostenere la prestazione di servizi EURES per l'assunzione e il collocamento dei lavoratori in posti di lavoro sostenibili e di qualità mediante l'intermediazione tra l'offerta e la domanda di lavoro; il sostegno a favore dei servizi EURES copre le varie fasi del collocamento, dalla preparazione precedente l'assunzione all'assistenza successiva al collocamento, e ha lo scopo di favorire la piena integrazione nel mercato del lavoro; tali servizi di sostegno possono comprendere programmi di mobilità miranti a coprire i posti di lavoro vacanti in un determinato settore, ambito professionale, paese o gruppo di paesi o per specifiche categorie di lavoratori, quali i giovani, con una propensione alla mobilità, dove è stata individuata una chiara necessità economica.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "21": {"label": "Articolo 21", "heading": "Tipi di azione", "anchor": "art_21", "frags": [[null, "<p class=\"oj-normal\">L'asse \"EURES\"può essere utilizzato per finanziare azioni dirette a promuovere la mobilità volontaria delle persone nell'Unione su una base equa e a eliminare gli ostacoli alla mobilità, in particolare:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo sviluppo di partenariati transfrontalieri EURES e le relative attività, se richieste dai servizi territorialmente responsabili per le regioni frontaliere;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">la fornitura di informazioni, consulenza e servizi di assunzione e collocamento per i lavoratori transfrontalieri;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo sviluppo di una piattaforma digitale multilingue per l'intermediazione tra l'offerta e la domanda di lavoro;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">d)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">lo sviluppo di programmi mirati di mobilità, a seguito di inviti a presentare proposte, per riempire posti vacanti dove sono state individuate carenze del mercato del lavoro, e/o per aiutare i lavoratori propensi alla mobilità e dove è stata individuata una chiara necessità economica;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">e)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">l'apprendimento reciproco tra gli attori EURES e la formazione dei consulenti EURES, compresi i consulenti per i partenariati transfrontalieri;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">f)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">attività di informazione e comunicazione per sensibilizzare in merito ai vantaggi della mobilità geografica e lavorativa, in generale, e delle attività e servizi forniti da EURES, in particolare.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "22": {"label": "Articolo 22", "heading": "Cofinanziamento dell'Unione", "anchor": "art_22", "frags": [[null, "<p class=\"oj-normal\">Nei casi in cui le attività dell'asse \"Eures\" siano finanziate a seguito di un invito a presentare proposte, esse possono beneficiare di un cofinanziamento dell'Unione non superiore, di norma, al 95 % della spesa totale ammissibile. Un eventuale sostegno finanziario superiore a tale massimale è concesso soltanto in circostanze eccezionali debitamente giustificate.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Monitoraggio delle tendenze di mobilità", "anchor": "art_23", "frags": [[null, "<p class=\"oj-normal\">Per individuare e prevenire le ripercussioni negative derivanti dalla mobilità geografica all'interno dell'Unione, la Commissione, congiuntamente agli Stati membri, effettua un monitoraggio periodico dei flussi e delle tendenze di mobilità, conformemente all'articolo 12 del regolamento (UE) n. 492/2011.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Partecipazione", "anchor": "art_24", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Possono partecipare all'asse \"EURES\":</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">gli Stati membri;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i paesi del SEE, in conformità dell'accordo SEE, e la Confederazione svizzera, in conformità dell'accordo tra la Comunità europea e i suoi Stati membri, da un lato, e la Confederazione svizzera, dall'altro, sulla libera circolazione delle persone (<span class=\"oj-super oj-note-tag\">18</span>).</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   L'asse \"EURES\" è aperto a tutti gli organismi, gli attori e le istituzioni designati da uno Stato membro o dalla Commissione che soddisfano le condizioni per la partecipazione a EURES definite nella decisione di esecuzione 2012/733/UE della Commissione. Tali organismi, attori e istituzioni comprendono in particolare:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le autorità nazionali, regionali e locali;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">i servizi per l'impiego;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le organizzazioni delle parti sociali e di altre parti interessate.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Sezioni tematiche e finanziamento", "anchor": "art_25", "frags": [[null, "<p class=\"oj-normal\">L'asse \"Microfinanza e imprenditoria sociale\" sostiene le azioni di una o più delle sezioni tematiche elencate alle lettere a) e b). Per l'intero periodo del programma, la dotazione indicativa di cui all'articolo 5, paragrafo 2, lettera c), è ripartita tra le diverse sezioni secondo le seguenti percentuali minime:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">microfinanziamenti per le categorie vulnerabili e le microimprese: 45 %;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">imprenditoria sociale: 45 %;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">Ogni importo restante è assegnato alle sezioni tematiche di cui alle lettere a) o b) o ad una combinazione delle stesse.</p>"]]}, "26": {"label": "Articolo 26", "heading": "Obiettivi specifici", "anchor": "art_26", "frags": [[null, "<p class=\"oj-normal\">Oltre agli obiettivi generali di cui all'articolo 4, l'asse \"Microfinanza e imprenditoria sociale\" persegue i seguenti obiettivi specifici:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">facilitare l'accesso alla microfinanza e accrescerne la disponibilità per:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">i)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le persone vulnerabili che hanno perso o rischiano di perdere il lavoro, incontrano difficoltà a entrare o a rientrare nel mercato del lavoro oppure rischiano l'esclusione sociale o sono socialmente escluse e che si trovano in una posizione svantaggiata per l'accesso al mercato del credito convenzionale e che desiderano avviare o sviluppare una microimpresa in proprio;</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">ii)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">le microimprese, sia in fase di avviamento che di sviluppo, in particolare le microimprese che occupano persone di cui alla lettera i);</p>\n</td>\n</tr>\n</tbody>\n</table>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sviluppare la capacità istituzionale degli operatori del microcredito;</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">c)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">sostenere lo sviluppo del mercato dell'investimento sociale e agevolare l'accesso al credito per le imprese sociali, mettendo a disposizione equity, quasi-equity, strumenti di prestito e sovvenzioni fino a 500 000 EUR per le imprese sociali che hanno un fatturato annuo non superiore ai 30 milioni di EUR ovvero un totale di bilancio annuo non superiore ai 30 milioni di EUR, e che non siano imprese di investimento collettivo.</p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<p class=\"oj-normal\">Per garantire la complementarità, la Commissione e gli Stati membri, nei rispettivi settori di competenza, coordinano strettamente tali azioni con quelle intraprese nel quadro della politica di coesione e delle politiche nazionali.</p>"]]}, "27": {"label": "Articolo 27", "heading": "Tipi di azione", "anchor": "art_27", "frags": [[null, "<p class=\"oj-normal\">Nell'ambito dell'asse \"Microfinanza e imprenditoria sociale\" può essere fornito sostegno alla microfinanza e alle imprese sociali, anche ai fini dello sviluppo delle capacità istituzionali, in particolare mediante gli strumenti finanziari di cui al titolo VIII della prima parte del regolamento finanziario, e sovvenzioni.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Partecipazione", "anchor": "art_28", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La partecipazione all'asse \"Microfinanza e imprenditoria sociale\" è aperta agli organismi pubblici e privati, stabiliti a livello nazionale, regionale o locale nei paesi di cui all'articolo 18, paragrafo 1, e che forniscono in tali paesi:</p>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">a)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">microfinanziamenti a persone e a microimprese; e/o</p>\n</td>\n</tr>\n</tbody>\n</table>\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">b)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">finanziamenti alle imprese sociali.</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione provvede affinché l'asse sia accessibile a tutti gli organismi pubblici e privati degli Stati membri, senza discriminazioni.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Al fine di raggiungere i beneficiari finali e di creare microimprese competitive e redditizie, gli organismi pubblici e privati che svolgono le attività di cui al paragrafo 1, lettera a), cooperano strettamente con le organizzazioni, comprese le organizzazioni della società civile, che rappresentano gli interessi dei beneficiari finali del microcredito e con altre organizzazioni, in particolare quelle sostenute dal FSE, e offrono ai beneficiari finali programmi di tutoraggio e di formazione. In tale contesto è garantito un seguito sufficiente dei beneficiari sia prima che dopo la creazione della microimpresa.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Gli organismi pubblici e privati che svolgono le attività di cui al paragrafo 1, lettera a), si attengono a standard elevati in materia di governance, gestione e tutela dei consumatori, secondo i principi del codice europeo di buona condotta per l'erogazione di microcrediti e si adoperano per prevenire l'indebitamento eccessivo di persone e imprese derivante, ad esempio, dalla concessione di credito a tassi elevati o a condizioni che possono determinare la loro insolvenza.</p>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Contributo finanziario", "anchor": "art_29", "frags": [[null, "<p class=\"oj-normal\">Tranne nel caso delle azioni comuni, la dotazione finanziaria assegnata all'asse \"Microfinanza e imprenditoria sociale\" copre l'intero costo delle azioni realizzate attraverso strumenti finanziari, compresi gli obblighi di pagamento nei confronti degli intermediari finanziari, come le perdite derivanti da garanzie, le spese di gestione per le entità che gestiscono il contributo dell'Unione e ogni altra spesa ammissibile.</p>"]]}, "30": {"label": "Articolo 30", "heading": "Gestione", "anchor": "art_30", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Per mettere in atto gli strumenti e le sovvenzioni di cui all'articolo 27, la Commissione può concludere accordi con le entità di cui all'articolo 139, paragrafo 4, del regolamento finanziario, in particolare con la Banca europea per gli investimenti e con il Fondo europeo per gli investimenti. Tali accordi contengono disposizioni dettagliate per l'attuazione dei compiti affidati a tali entità, comprese disposizioni che specificano la necessità di garantire l'addizionalità e il coordinamento rispetto agli esistenti strumenti finanziari dell'Unione e nazionali e di ripartire le risorse in modo equilibrato tra gli Stati membri e gli altri paesi partecipanti. Gli strumenti finanziari di cui al titolo VIII della prima parte del regolamento finanziario possono essere forniti attraverso un veicolo di investimento dedicato, finanziabile dai fondi del programma, da altri investitori o da entrambi.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il veicolo di investimento dedicato di cui al paragrafo 1 può fornire, tra l'altro, prestiti, capitali di rischio e strumenti di condivisione del rischio agli intermediari o provvedere al finanziamento diretto delle imprese sociali, o entrambe le cose. Il capitale di rischio può essere fornito tra l'altro sotto forma di partecipazioni aperte, associazioni in partecipazione, prestiti partecipativi nonché combinazioni di vari tipi di partecipazioni emesse per gli investitori.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Le condizioni, come i tassi di interesse, per i microcrediti direttamente o indirettamente sostenuti nel quadro del presente asse sono commensurate ai benefici del sostegno e giustificabili in relazione ai rischi sottostanti e al costo effettivo dei finanziamenti connessi a un credito.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Conformemente all'articolo 140, paragrafo 6, del regolamento finanziario, i rimborsi annuali generati da uno strumento finanziario sono assegnati a tale strumento finanziario fino al 1<span class=\"oj-super\">o</span> gennaio 2024, mentre le entrate sono iscritte nel bilancio generale dell'Unione previa detrazione dei costi di gestione e delle tasse. Per gli strumenti finanziari già istituiti nel quadro finanziario pluriennale per il periodo 2007-2013, i rimborsi annuali e le entrate generati da operazioni iniziate nel periodo precedente sono assegnati allo strumento finanziario nel periodo in corso.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   Allo scadere degli accordi conclusi con le entità di cui al paragrafo 1, o al termine del periodo di investimento del veicolo di investimento specializzato, il saldo dovuto all'Unione è versato al bilancio generale dell'Unione.</p>\n</div>"], [6, "<div>\n<p class=\"oj-normal\">6.   Le entità di cui al paragrafo 1 del presente articolo, e, se del caso, i gestori dei fondi concludono accordi scritti con gli organismi pubblici e privati di cui all'articolo 28. Tali accordi stabiliscono gli obblighi dei soggetti erogatori pubblici e privati di utilizzare le risorse messe a disposizione nel quadro dell'asse \"Microfinanza e imprenditoria sociale\" in conformità degli obiettivi stabiliti all'articolo 26 e di fornire informazioni per la stesura delle relazioni annuali sullo stato di attuazione di cui all'articolo 31.</p>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Relazioni sullo stato di attuazione", "anchor": "art_31", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Le entità di cui all'articolo 30, paragrafo 1, e, se del caso, i gestori dei fondi trasmettono alla Commissione relazioni annuali sullo stato di attuazione che descrivono le attività che sono state sovvenzionate, la loro esecuzione finanziaria, la ripartizione e l'accessibilità dei finanziamenti e degli investimenti per settore, l'area geografica e il tipo di beneficiario. Tali relazioni indicano inoltre le domande accettate o respinte riguardo a ogni obiettivo specifico e i contratti conclusi dagli organismi pubblici e privati interessati, le azioni finanziate e i risultati, anche in termini della loro incidenza sociale, creazione di posti di lavoro e sostenibilità delle sovvenzioni concesse. La Commissione trasmette tali relazioni al Parlamento europeo a scopo informativo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Le informazioni fornite in tali relazioni annuali sullo stato di attuazione sono riprese nelle relazioni biennali di monitoraggio di cui all'articolo 12. Le relazioni di monitoraggio comprendono le relazioni annuali di cui all'articolo 8, paragrafo 2, della decisione n. 283/2010/UE e riportano informazioni particolareggiate sulle attività di comunicazione e informazioni sulla complementarietà con altri strumenti dell'Unione, in particolare con il FSE.</p>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Programmi di lavoro", "anchor": "art_32", "frags": [[null, "<p class=\"oj-normal\">La Commissione adotta atti di esecuzione che stabiliscono programmi di lavoro per i tre assi. Tali atti di esecuzione sono addottati secondo la procedura d'esame di cui all'articolo 36, paragrafo 3.</p>"], [null, "<p class=\"oj-normal\">I programmi di lavoro si svolgono, se del caso, per un periodo continuo di tre anni e contiene una descrizione delle azioni da finanziare, le procedure di selezione delle azioni che l'Unione dovrà finanziare, la copertura geografica, i destinatari e un calendario indicativo di attuazione. I programmi di lavoro comprendono altresì un'indicazione dell'importo stanziato a ciascun obiettivo specifico e riflettono la riassegnazione dei fondi ai temi prioritari all'interno di ciascun asse ai sensi dell'articolo 33. I programmi di lavoro rafforzano la coerenza del programma indicando i collegamenti fra i tre assi.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Riassegnazione dei fondi tra gli assi e alle singole sezioni tematiche all'interno degli assi", "anchor": "art_33", "frags": [[null, "<p class=\"oj-normal\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all'articolo 34 riguardo alla riassegnazione dei fondi tra gli assi e, al loro interno, alle singole sezioni tematiche nel caso in cui tali fondi superino l'importo indicativo fissato per ciascun caso di una percentuale compresa tra il 5 % e il 10 %, qualora tale necessità sia dettata dall'evoluzione del contesto socioeconomico o dai risultati della valutazione intermedia di cui all'articolo 13, paragrafo 1. La riassegnazione dei fondi alle sezioni tematiche all'interno di ciascun asse è ripresa nei programmi di lavoro di cui all'articolo 32.</p>"]]}, "34": {"label": "Articolo 34", "heading": "Esercizio della delega", "anchor": "art_34", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Il potere di adottare atti delegati di cui all'articolo 33 è conferito alla Commissione per un periodo di sette anni a decorrere dal 1<span class=\"oj-super\">o</span> gennaio 2014.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   La delega di potere di cui all'articolo 33 può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella Gazzetta ufficiale dell'Unione europea o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</p>\n</div>"], [4, "<div>\n<p class=\"oj-normal\">4.   Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</p>\n</div>"], [5, "<div>\n<p class=\"oj-normal\">5.   L'atto delegato adottato ai sensi dell'articolo 33 entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</p>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Misure di esecuzione supplementari", "anchor": "art_35", "frags": [[null, "<p class=\"oj-normal\">Le misure necessarie all'esecuzione del programma, quali i criteri di valutazione dello stesso, compresi i criteri relativi al rapporto costo-efficacia e alle modalità di diffusione e trasferimento dei risultati, sono adottate secondo la procedura consultiva di cui all'articolo 36, paragrafo 2.</p>"]]}, "36": {"label": "Articolo 36", "heading": "Procedura di comitato", "anchor": "art_36", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La Commissione è assistita da un comitato. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 4 del regolamento (UE) n. 182/2011.</p>\n</div>"], [3, "<div>\n<p class=\"oj-normal\">3.   Nei casi in cui è fatto riferimento al presente paragrafo, si applica l'articolo 5 del regolamento (UE) n. 182/2011.</p>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Disposizioni transitorie", "anchor": "art_37", "frags": [[null, "<p class=\"oj-normal\">Le azioni di cui agli articoli 4, 5 e 6 della decisione n. 1672/2006/CE avviate prima del 1<span class=\"oj-super\">o</span> gennaio 2014 continuano ad essere disciplinate da tale decisione. Per quanto riguarda tali azioni, la Commissione è assistita dal comitato di cui all'articolo 36 del presente regolamento.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Valutazione", "anchor": "art_38", "frags": [[1, "<div>\n<p class=\"oj-normal\">1.   La valutazione finale di cui all'articolo 13, paragrafo 4, del presente regolamento comprende la valutazione finale di cui all'articolo 9 della decisione n. 283/2010/UE.</p>\n</div>"], [2, "<div>\n<p class=\"oj-normal\">2.   La Commissione effettua una valutazione finale specifica dell'asse \"Microfinanza e imprenditoria sociale\" entro l'anno che segue la scadenza degli accordi con le entità.</p>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Modifiche della decisione n. 283/2010/UE", "anchor": "art_39", "frags": [[null, "<p class=\"oj-normal\">La decisione n. 283/2010/UE è così modificata:</p>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">1)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">all'articolo 5, il paragrafo 4 è sostituito dal seguente:</p>\n<div>\n<p class=\"oj-normal\">\"4.   Allo scadere dello strumento di microfinanza, il saldo residuo dovuto all'Unione europea è messo a disposizione per microfinanziamenti e per il sostegno a imprese sociali in conformità del regolamento (UE) n. 1296/2013 del Parlamento europeo e del Consiglio, del 11 dicembre 2013, relativo a un programma dell'Unione europea per l'occupazione e l'innovazione sociale (\"EaSI\") (<span class=\"oj-super oj-note-tag\">*1</span>).</p>\n</div>\n<p class=\"oj-note\">\n(<span class=\"oj-super\">*1</span>)  \n                                          GU L 347 del 20.12.2013, pag. 238\";\"\n                        </p>\n</td>\n</tr>\n</tbody>\n</table>"], [null, "<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\" width=\"100%\">\n<col width=\"4%\"/>\n<col width=\"96%\"/>\n<tbody>\n<tr>\n<td valign=\"top\">\n<p class=\"oj-normal\">2)</p>\n</td>\n<td valign=\"top\">\n<p class=\"oj-normal\">all'articolo 8, i paragrafi 3 e 4 sono soppressi.</p>\n</td>\n</tr>\n</tbody>\n</table>"]]}, "40": {"label": "Articolo 40", "heading": "Entrata in vigore", "anchor": "art_40", "frags": [[null, "<p class=\"oj-normal\">Il presente regolamento entra in vigore il giorno successivo alla pubblicazione nella <span class=\"oj-italic\">Gazzetta ufficiale dell'Unione europea</span>.</p>"]]}}, "recitals": {}};